def positive_float(value):
    try:
        return max(0, float(value or 0))
    except Exception:
        return 0

def ceil_positive(value):
    whole = int(value)
    if value > whole:
        return whole + 1
    return whole

def round_up_to_even_inch(value):
    whole = ceil_positive(positive_float(value))
    if whole <= 0:
        return 0
    if whole % 2:
        return whole + 1
    return whole

def truthy(value):
    return str(value or '').strip().lower() in ('1', 'true', 'yes', 'y')

def size_key(height, width, use_billable_size):
    if use_billable_size:
        h = round_up_to_even_inch(height)
        w = round_up_to_even_inch(width)
    else:
        h = ceil_positive(positive_float(height))
        w = ceil_positive(positive_float(width))

    if not h or not w:
        return ''

    low = min(h, w)
    high = max(h, w)
    return '{}x{}'.format(high, low)

prices = {
    '20.25m': {
        '22x11': {'polish': 26, 'ruf': 25},
        '22x16': {'polish': 31},
        '22x22': {'polish': 32},
    },
    '25.30m': {
        '22x16': {'polish': 33, 'ruf': 30},
        '23x17': {'polish': 35},
        '22x22': {'polish': 34, 'ruf': 32},
        '23x23': {'polish': 35},
    },
    'gadela': {
        '24x18': {'polish': 38},
        '24x24': {'polish': 39},
    },
}

args = frappe.form_dict
item_code = str(args.get('item_code') or '').lower()
height = positive_float(args.get('height') or args.get('custom_height'))
width = positive_float(args.get('width') or args.get('custom_width'))
required_area_sqft = positive_float(args.get('required_area_sqft') or args.get('area_sqft'))
finish = str(args.get('finish') or '').strip().lower()
price_section = str(args.get('price_section') or '').strip().lower()

if not finish:
    if 'ruf' in item_code or 'rough' in item_code or 'rou' in item_code:
        finish = 'ruf'
    else:
        finish = 'polish'

is_gadela = truthy(args.get('is_gadela')) or 'gadela' in item_code or ' raj g' in (' ' + item_code + ' ')
if not price_section:
    price_section = 'gadela' if is_gadela else '25.30m'

stone_coverage_sqft = (height * width) / 144 if height and width else 0
if not height or not width or not required_area_sqft or not stone_coverage_sqft:
    frappe.response['message'] = {
        'ok': False,
        'error': 'height, width, and required_area_sqft are required positive numbers',
    }
else:
    key = size_key(height, width, price_section == 'gadela')
    price_row = prices.get(price_section, {}).get(key)

    if not price_row:
        frappe.response['message'] = {
            'ok': False,
            'error': 'price not found for section {} and size {}'.format(price_section, key),
            'size_key': key,
            'price_section': price_section,
        }
    else:
        rate = price_row.get(finish) or price_row.get('polish')
        stones_needed = ceil_positive(required_area_sqft / stone_coverage_sqft)
        billable_height = round_up_to_even_inch(height)
        billable_width = round_up_to_even_inch(width)
        billable_area_sqft = round(stones_needed * ((billable_height * billable_width) / 144), 4)
        amount = round(billable_area_sqft * rate, 2)

        frappe.response['message'] = {
            'ok': True,
            'item_code': args.get('item_code'),
            'height': height,
            'width': width,
            'required_area_sqft': required_area_sqft,
            'stone_coverage_sqft': round(stone_coverage_sqft, 4),
            'stones_needed': stones_needed,
            'billable_height': billable_height,
            'billable_width': billable_width,
            'billable_area_sqft': billable_area_sqft,
            'price_section': price_section,
            'size_key': key,
            'finish': finish,
            'rate': rate,
            'amount': amount,
        }
